ci-parse-age.solutionCode:
def parse_age(text):
    cleaned = text.strip()
    try:
        return int(cleaned)
    except ValueError:
        return None

ci-clean-row.solutionCode:
def clean_row(row):
    name = row[0].strip()
    score_text = row[1].strip()

    if name == "":
        return None

    try:
        score = int(score_text)
    except ValueError:
        return None

    return {"name": name.title(), "score": score}

